ValidationRule.errorConditionFormula:
AND(
    NOT(ISBLANK(IBAN__c)),
    /* Die bereinigte Länge muss ungleich der definierten Länge des jeweiligen Landes sein */
    LEN(SUBSTITUTE(IBAN__c, " ", "")) <> 
    CASE(UPPER(LEFT(SUBSTITUTE(IBAN__c, " ", ""), 2)),
        /* --- EUROPÄISCHE UNION --- */
        "AT", 20, "BE", 16, "BG", 22, "CY", 28, "CZ", 24,
        "DE", 22, "DK", 18, "EE", 20, "ES", 24, "FI", 18,
        "FR", 27, "GR", 27, "HR", 21, "HU", 28, "IE", 22,
        "IT", 27, "LT", 20, "LU", 20, "LV", 21, "MT", 31,
        "NL", 18, "PL", 28, "PT", 25, "RO", 24, "SE", 24,
        "SI", 19, "SK", 24,
        /* --- ARABISCHE HALBINSEL --- */
        "AE", 23, /* Ver. Arab. Emirate */
        "BH", 22, /* Bahrain */
        "KW", 30, /* Kuwait */
        "OM", 31, /* Oman */
        "QA", 29, /* Katar */
        "SA", 24, /* Saudi-Arabien */
        /* Jemen nutzt kein IBAN-System */
        /* --- BRICS (IBAN-Nutzer) --- */
        "BR", 29, /* Brasilien */
        "RU", 33, /* Russland */
        "EG", 29, /* Ägypten */
        "IR", 26, /* Iran */
        /* Indien, China, Südafrika nutzen kein IBAN-System */
        /* --- FALLBACK --- */
        LEN(SUBSTITUTE(IBAN__c, " ", ""))
    )
)
